        <TabPanel>
          <Columns columns={3} gap="large">
            <Card>
              <Stack space="medium">
                <Heading level="3">Slack</Heading>
                <Badge variant="success">Connected</Badge>
                <Text size="small">Integration with Slack for notifications and updates</Text>
